import React, { useEffect, useState } from 'react';
import mapboxgl from 'mapbox-gl';
import 'mapbox-gl/dist/mapbox-gl.css';
import { FoodSpot } from '../types';
import { foodService } from '../services/foodService';
import FoodCard from '../components/FoodCard';

const LocalFoodSpots: React.FC = () => {
	const [spots, setSpots] = useState<FoodSpot[]>([]);
	const [loading, setLoading] = useState(true);
	const [error, setError] = useState<string | null>(null);
	const [map, setMap] = useState<mapboxgl.Map | null>(null);

	useEffect(() => {
		const fetchFoodSpots = async () => {
			try {
				setLoading(true);
				const data = await foodService.getFoodSpots();
				setSpots(data);
			} catch (err) {
				setError('Failed to load food spots');
				console.error(err);
			} finally {
				setLoading(false);
			}
		};

		fetchFoodSpots();
	}, []);

	useEffect(() => {
		// Initialize map
		const mapboxToken = process.env.REACT_APP_MAPBOX_ACCESS_TOKEN;
		if (!mapboxToken) {
			console.warn('Mapbox access token not found');
			return;
		}

		mapboxgl.accessToken = mapboxToken;

		const mapInstance = new mapboxgl.Map({
			container: 'map',
			style: 'mapbox://styles/mapbox/streets-v11',
			center: [-80.8431, 35.2271], // Charlotte, NC
			zoom: 12,
		});

		mapInstance.on('load', () => {
			// Add markers for food spots
			spots.forEach((spot) => {
				if (spot.latitude && spot.longitude) {
					const marker = new mapboxgl.Marker()
						.setLngLat([spot.longitude, spot.latitude])
						.setPopup(
							new mapboxgl.Popup({ offset: 25 }).setHTML(
								`<h3>${spot.name}</h3><p>${spot.category}</p><p>Rating: ${spot.rating}</p>`
							)
						)
						.addTo(mapInstance);
				}
			});
		});

		setMap(mapInstance);

		return () => {
			mapInstance.remove();
		};
	}, [spots]);

	return (
		<div className="min-h-screen bg-gray-50">
			<div className="container mx-auto px-4 py-8">
				<h1 className="text-3xl font-bold text-uncc-green mb-6">
					Local Food Spots in Charlotte
				</h1>

				<div className="flex flex-col lg:flex-row gap-6">
					{/* Map Section */}
					<div className="lg:w-1/2">
						<div
							id="map"
							className="w-full h-96 lg:h-[600px] rounded-lg shadow-lg"
							style={{ backgroundColor: '#f0f0f0' }}
						>
							{!process.env.REACT_APP_MAPBOX_ACCESS_TOKEN && (
								<div className="w-full h-full flex items-center justify-center bg-gray-200 rounded-lg">
									<div className="text-center">
										<div className="text-4xl mb-4">🗺️</div>
										<div className="text-gray-600">
											Map integration requires Mapbox token
										</div>
									</div>
								</div>
							)}
						</div>
					</div>

					{/* Food Spots List */}
					<div className="lg:w-1/2">
						{loading ? (
							<div className="bg-white rounded-lg shadow-lg p-8">
								<div className="flex items-center justify-center py-8">
									<div className="animate-spin rounded-full h-8 w-8 border-b-2 border-uncc-green mr-3"></div>
									<span className="text-gray-600">Loading food spots...</span>
								</div>
							</div>
						) : error ? (
							<div className="bg-white rounded-lg shadow-lg p-8">
								<div className="bg-red-100 border-l-4 border-red-500 text-red-700 p-4 rounded">
									{error}
								</div>
							</div>
						) : (
							<div className="bg-white rounded-lg shadow-lg p-6">
								<h2 className="text-xl font-bold text-gray-800 mb-4">
									Restaurants, Cafes & Bars ({spots.length})
								</h2>
								<div className="space-y-4 max-h-[600px] overflow-y-auto">
									{spots.map((spot) => (
										<FoodCard key={spot.id} spot={spot} />
									))}
								</div>
							</div>
						)}
					</div>
				</div>
			</div>
		</div>
	);
};

export default LocalFoodSpots;
